<template>
  <div :style="{background: convertToColor(automationUsageInfo.percentage)}" class="card-panel">
    <el-row :gutter="20">
      <el-col :span="24">
        <div class="card-panel-description">
          <div class="card-panel-text">{{ automationUsageInfo.collabName }}
            <el-tooltip class="item" effect="dark" content="Status Current Build From Jenkins " placement="top">
              <i :class="convertToIcon(automationUsageInfo.statusBuild)"/>
            </el-tooltip>
          </div>
        </div>
      </el-col>
    </el-row>
    <el-row>
      <el-col :span="8">
        <div class="card-panel-icon-wrapper" style="font-size: 25px;float: left">
          <el-tooltip class="item" effect="dark" content="Total % Automation Daily Usage , The Formula is Total automation that run daily in jenkins divided by Total Automation that avaiable in the testlink * 100%" placement="top">
            <count-to :start-val="0" :end-val="automationUsageInfo.percentage" :duration="1500" suffix=" %"/>
          </el-tooltip>
        </div>
      </el-col>
      <el-col :span="16" style="font-size: 12px">
        <el-row class="row-margin">
          <el-tooltip class="item" effect="dark" content="Total Automation From Testlink" placement="top">
            <el-col :span="8">
              <div style="font-weight: bold">Total</div>
              <div style="margin-top: 5px">
                <count-to :start-val="0" :end-val="automationUsageInfo.totalAutomation" :duration="1500" separator="."/>
              </div>
            </el-col>
          </el-tooltip>
          <el-tooltip class="item" effect="dark" content="Total Automation That run in jenkins" placement="top">
            <el-col :span="8">
              <div style="font-weight: bold">Usage</div>
              <div style="margin-top: 5px">
                <count-to :start-val="0" :end-val="automationUsageInfo.totalUsage" :duration="1500" separator="."/>
              </div>
            </el-col>
          </el-tooltip>
          <el-tooltip class="item" effect="dark" content="Total Automation That run and Passed in Jenkins" placement="top">
            <el-col :span="8">
              <div style="font-weight: bold">Success</div>
              <div style="margin-top: 5px">
                <count-to :start-val="0" :end-val="automationUsageInfo.totalSuccess" :duration="1500" separator="."/>
              </div>
            </el-col>
          </el-tooltip>
        </el-row>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import CountTo from 'vue-count-to'

export default {
  components: {
    CountTo
  },
  props: {
    // collabName: {
    //   type: String,
    //   required: true
    // },
    // bgColor: {
    //   type: String,
    //   required: true
    // },
    // manualTest: {
    //   type: Number,
    //   required: true
    // }, automation: {
    //   type: Number,
    //   required: true
    // }, automatedTest: {
    //   type: Number,
    //   required: true
    // }
    automationUsageInfo: {
      type: Object,
      required: true
    }
  },
  methods: {
    convertToColor(value) {
      // console.log(value)
      if (value >= this.automationUsageInfo.green) {
        return '#5cb85c'
      } else if (value >= this.automationUsageInfo.yellow) {
        return '#f0ad4e'
      } else {
        return '#d9534f'
      }
    },
    convertToIcon(status) {
      if (status === 'blue') {
        return 'el-icon-success'
      } else if (status === 'yellow') {
        return 'el-icon-warning'
      } else {
        return 'el-icon-error'
      }
    }
  }
}
</script>

